import java.io.IOException;

public class CommandInjectionFixed {
    public static void main(String[] args) throws IOException {
        String userInput = "127.0.0.1; ls"; // User input with potential malicious commands

        // Validate and sanitize user input to only allow valid input (e.g., IP address)
        if (!userInput.matches("[0-9.]+")) {
            System.out.println("Invalid input");
            return;
        }

        // Constructing a command using user input with ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder("ping", userInput);
        Process process = processBuilder.start(); // Start the process

        // Read the output of the command
        java.util.Scanner scanner = new java.util.Scanner(process.getInputStream());
        while (scanner.hasNextLine()) {
            System.out.println(scanner.nextLine());
        }
    }
}

